class Solution {
    private static final int MOD = (int) 1e9 + 7;
    public int countGoodStrings(int low, int high, int zero, int one) {
        int[][] dp = new int[high + 1][2];
        dp[0][0] = dp[0][1] = 1;
        int res = 0;
        for (int i = low; i <= high; i++) {
            if (i >= zero) dp[i][0] = (dp[i - zero][0] + dp[i - zero][1]) % MOD;
            if (i >= one) dp[i][1] = (dp[i - one][0] + dp[i - one][1]) % MOD;
            res = (res + dp[i][0] + dp[i][1]) % MOD;
        }
        return res;
    }
}
